"""Tests for the hook HTTP server."""

import json
import threading
import urllib.request

from claude_dashboard.hook_server import HookServer
from claude_dashboard.config import StatusState


class TestHookServer:
    def test_receives_hook_event(self):
        """POST a hook event and verify the callback fires."""
        received: list[tuple[str, str, StatusState]] = []
        event = threading.Event()

        def on_hook(session_id, hook_event, state, cwd=""):
            received.append((session_id, hook_event, state))
            event.set()

        server = HookServer(
            on_hook_event=on_hook,
            on_session_end=lambda sid: None,
            port=0,  # OS-assigned port
        )
        server.start()

        try:
            payload = json.dumps(
                {
                    "session_id": "test-session-123",
                    "hook_event_name": "Stop",
                    "cwd": "/tmp/test",
                }
            ).encode()

            req = urllib.request.Request(
                f"http://127.0.0.1:{server.port}/hook",
                data=payload,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urllib.request.urlopen(req, timeout=5) as resp:
                assert resp.status == 200

            event.wait(timeout=2)
            assert len(received) == 1
            assert received[0] == ("test-session-123", "Stop", StatusState.IDLE)
        finally:
            server.stop()

