    def test_session_end_fires_callback(self):
        """SessionEnd hook fires the on_session_end callback."""
        ended: list[str] = []
        event = threading.Event()

        def on_end(session_id):
            ended.append(session_id)
            event.set()

        server = HookServer(
            on_hook_event=lambda *a: None,
            on_session_end=on_end,
            port=0,
        )
        server.start()

        try:
            payload = json.dumps(
                {
                    "session_id": "ending-session",
                    "hook_event_name": "SessionEnd",
                }
            ).encode()

            req = urllib.request.Request(
                f"http://127.0.0.1:{server.port}/hook",
                data=payload,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            with urllib.request.urlopen(req, timeout=5):
                pass

            event.wait(timeout=2)
            assert ended == ["ending-session"]
        finally:
            server.stop()

    def test_empty_body_returns_400(self):
        """POST with invalid body returns 400."""
        server = HookServer(
            on_hook_event=lambda *a: None,
            on_session_end=lambda s: None,
            port=0,
        )
        server.start()

        try:
            req = urllib.request.Request(
                f"http://127.0.0.1:{server.port}/hook",
                data=b"not json",
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            try:
                urllib.request.urlopen(req, timeout=5)
                assert False, "Expected HTTP error"
            except urllib.error.HTTPError as e:
                assert e.code == 400
        finally:
            server.stop()
